  relatedFrameworkIds: [`utilitarianism`, `deontology`, `virtue-ethics`],
  relatedPhilosopherIds: [`mill`, `singer`, `kant`, `rawls`],
  relatedAuthorIds: [`isaac-asimov`, `liu-cixin`, `octavia-butler`, `philip-k-dick`],
